import React, { useState } from 'react';
import FullCalendar from '@fullcalendar/react'; // Importa o componente de calendário
import dayGridPlugin from '@fullcalendar/daygrid'; // Plugin para a visão do mês
import timeGridPlugin from '@fullcalendar/timegrid'; // Plugin para visão semanal
import interactionPlugin from '@fullcalendar/interaction'; // Plugin para interatividade
import './Calendar.css'; // Importa o arquivo de estilos do calendário

const Calendar = () => {
  const [events, setEvents] = useState([
    { title: 'Nossa Senhora Aparecida', start: '2024-10-12' } // Evento de exemplo
  ]);

  return (
    <div className="calendar-container">
      <h2 className="calendar-title">Agenda</h2> {/* Título da agenda */}
      <FullCalendar
        plugins={[dayGridPlugin, timeGridPlugin, interactionPlugin]} // Plugins de visão do calendário
        initialView="dayGridMonth" // Inicializa o calendário na visão mensal
        headerToolbar={{
          left: 'prev,next today',
          center: 'title',
          right: 'dayGridMonth,timeGridWeek,timeGridDay'
        }} // Botões de navegação e controle
        events={events} // Eventos a serem exibidos no calendário
        locale="pt-br" // Define o calendário no idioma português
        buttonText={{
          today: 'Hoje',
          month: 'Mês',
          week: 'Semana',
          day: 'Dia'
        }} // Tradução dos textos dos botões
        height="auto" // Ajusta a altura do calendário de acordo com o container
      />
    </div>
  );
};

export default Calendar;
